if (! function_exists('csv_grid_mapper_v2')) {
    function csv_grid_mapper_v2($csv_content, $grid_name, $value_column = null, $label_column = null, $max_rows = null, $truncate_length = null)
    {
                $rows = array_map('str_getcsv', explode("\n", trim($csv_content)));
                if (count($rows) < 2) { return ['error' => 'CSV must have header + data rows']; }

                $headers = array_map('trim', $rows[0]);
                $data = [];
                for ($i = 1; $i < count($rows); $i++) {
                    if (count($rows[$i]) === count($headers)) {
                        $data[] = array_combine($headers, array_map('trim', $rows[$i]));
                    }
                }
                if (empty($data)) { return ['error' => 'No valid data rows']; }

                require_once __DIR__ . '/text_coordinate_grid.php';

                // text_coordinate_grid signature: ($grid_name, $operation, $x, $y, $nx, $ny, $x2, $y2, $token)
                // We need token as the 9th param. Use a helper closure.
                $place = function($g, $x, $y, $tok) {
                    return text_coordinate_grid($g, 'place', $x, $y, null, null, null, null, $tok);
                };

                // Clear grid
                text_coordinate_grid($grid_name, 'clear');

                if ($value_column && !in_array($value_column, $headers)) {
                    $lc = array_map('strtolower', $headers);
                    $idx = array_search(strtolower($value_column), $lc);
                    if ($idx !== false) { $value_column = $headers[$idx]; }
                    else { return ['error' => "Column '$value_column' not found"]; }
                }
                if ($label_column && !in_array($label_column, $headers)) {
                    $lc = array_map('strtolower', $headers);
                    $idx = array_search(strtolower($label_column), $lc);
                    if ($idx !== false) { $label_column = $headers[$idx]; }
                    else { return ['error' => "Label column '$label_column' not found"]; }
                }

                $trunc = ($truncate_length > 0) ? $truncate_length : null;
                $placed = 0;

                if ($value_column !== null) {
                    if ($label_column !== null) {
                        $place($grid_name, 0, 0, (string)$label_column);
                        $place($grid_name, 1, 0, (string)$value_column);
                        $limit = min(count($data), $max_rows ?? 50);
                        for ($r = 0; $r < $limit; $r++) {
                            $label = $trunc ? mb_substr((string)$data[$r][$label_column], 0, $trunc) : (string)$data[$r][$label_column];
                            $val = $trunc ? mb_substr((string)$data[$r][$value_column], 0, $trunc) : (string)$data[$r][$value_column];
                            $place($grid_name, 0, $r + 1, $label);
                            $place($grid_name, 1, $r + 1, $val);
                            $placed++;
                        }
                    } else {
                        $place($grid_name, 0, 0, (string)$value_column);
                        $limit = min(count($data), $max_rows ?? 50);
                        for ($r = 0; $r < $limit; $r++) {
                            $val = $trunc ? mb_substr((string)$data[$r][$value_column], 0, $trunc) : (string)$data[$r][$value_column];
                            $place($grid_name, 0, $r + 1, $val);
                            $placed++;
                        }
                    }
                } else {
                    for ($c = 0; $c < count($headers); $c++) {
                        $place($grid_name, $c, 0, $trunc ? mb_substr($headers[$c], 0, $trunc) : $headers[$c]);
                    }
                    $limit = min(count($data), $max_rows ?? 50);
                    for ($r = 0; $r < $limit; $r++) {
                        for ($c = 0; $c < count($headers); $c++) {
                            $val = $trunc ? mb_substr((string)$data[$r][$headers[$c]], 0, $trunc) : (string)$data[$r][$headers[$c]];
                            $place($grid_name, $c, $r + 1, $val);
                        }
                        $placed++;
                    }
                }

                return [
                    'ok' => true, 'grid_name' => $grid_name,
                    'rows_imported' => $placed, 'columns' => count($headers),
                    'next_step' => "Use coordinate_grid_renderer(grid_name='$grid_name') to render as grid"
                ];
    }
}
